219	void fill_in_activation_sizes(const ActivationTensors* data, TensorSpec (&tensors)[NUM_ACTIVATION_TENSORS], size_t B, size_t T, GPT2Config config, int recompute) {
220	    size_t Vp = config.padded_vocab_size;
221	    size_t L = config.num_layers;
222	    size_t NH = config.num_heads;
223	    size_t C = config.channels;
224	    tensors[0] = TENSOR_SPEC(data->encoded, B * T * C);
225	    // if recompute >= 1 then we will recompute the layernorm forward activation during backward pass
226	    tensors[1] = TENSOR_SPEC(data->ln1,  (recompute < 2) ? L * B * T * C : 0);
227	    tensors[2] = TENSOR_SPEC(data->ln1_mean, L * B * T);
228	    tensors[3] = TENSOR_SPEC(data->ln1_rstd, L * B * T);
229	    tensors[4] = TENSOR_SPEC(data->atty, L * B * T * C);
230	    #ifdef ENABLE_CUDNN
231	    // FP32 stats tensor for cuDNN to be passed to backward pass
232	    tensors[5] = TENSOR_SPEC(data->att, L * B * NH * T);
233	    #else
234	    tensors[5] = TENSOR_SPEC(data->att, L * B * NH * T * T);
235	    #endif
236	    tensors[6] = TENSOR_SPEC(data->residual2, L * B * T * C);
237	    // if recompute >= 1 then we will recompute the layernorm forward activation during backward pass
238	    tensors[7] = TENSOR_SPEC(data->ln2, (recompute < 2) ? L * B * T * C : 0);
239	    tensors[8] = TENSOR_SPEC(data->ln2_mean, L * B * T);
240	    tensors[9] = TENSOR_SPEC(data->ln2_rstd, L * B * T);
241	    tensors[10] = TENSOR_SPEC(data->fch, L * B * T * 4*C);
242	    // if recompute >= 1 then we will recompute gelu_forward during backward and use this as scratch buffer
243	    tensors[11] = TENSOR_SPEC(data->fch_gelu, (recompute < 1) ? L * B * T * 4*C : B * T * 4*C);
244	    tensors[12] = TENSOR_SPEC(data->residual3, L * B * T * C);
245	    tensors[13] = TENSOR_SPEC(data->lnf, B * T * C);
246	    tensors[14] = TENSOR_SPEC(data->lnf_mean, B * T);
247	    tensors[15] = TENSOR_SPEC(data->lnf_rstd, B * T);
248	    tensors[16] = TENSOR_SPEC(data->losses, B * T);
249	    tensors[17] = TENSOR_SPEC(data->qkvr, L * B * T * 3*C);
250	    tensors[18] = TENSOR_SPEC(data->output, B * T * max(3*C, max(NH*T, Vp)));
251	
252	    tensors[19] = TENSOR_SPEC(data->scratch_bt4c, B * T * 4 * C);
253	    tensors[20] = TENSOR_SPEC(data->scratch_btc, B * T * C);
254	}
