256	void* malloc_and_point_activations(TensorSpec (&tensors)[NUM_ACTIVATION_TENSORS]) {
257	    size_t bytes = 0;
258	    for (size_t i = 0; i < NUM_ACTIVATION_TENSORS; i++) {
259	        bytes += tensors[i].size * sizeof_dtype(tensors[i].type);
260	    }
261	
262	    printf0("allocating %d MiB for activations\n", (int)round(bytes / (1024 * 1024)));
263	
264	    void* acts_memory;
265	    cudaCheck(cudaMalloc((void**)&acts_memory, bytes));
266	
267	    // cudaMalloc does not guarantee initial memory values so we memset the allocation here
268	    // this matters because e.g. non-cuDNN attention assumes the attention buffer is zeroed
269	    // todo - up to ~100ms on slow GPUs, could theoretically be more selective, but this is safer
270	    cudaCheck(cudaMemset(acts_memory, 0, bytes));
271	
272	    char* acts_memory_iterator = (char*)acts_memory;
273	    for (size_t i = 0; i < NUM_ACTIVATION_TENSORS; i++) {
274	        // extra protection so we don't accidentally use an empty buffer
275	        if(tensors[i].size == 0) {
276	            *(tensors[i].ptr) = NULL;
277	        }else {
278	            *(tensors[i].ptr) = acts_memory_iterator;
279	            acts_memory_iterator += tensors[i].size * sizeof_dtype(tensors[i].type);
280	        }
281	    }
282	    return acts_memory;
283	}
