324	void gpt2_init_common(GPT2 *model) {
325	    // common inits outside of the model weights
326	    // memory lazily initialized in forward()
327	    model->acts_memory = NULL;
328	    model->inputs = NULL;
329	    model->targets = NULL;
330	    model->accumulated_mean_loss = NULL;
331	    model->cpu_losses = NULL;
332	    // the B,T params are determined and set, fixed on first batch in forward()
333	    model->batch_size = 0;
334	    model->seq_len = 0;
335	    model->mean_loss = -1.0f; // -1.0f designates no loss, set at end of forward()
336	    model->params_memory = NULL;
337	    // memory lazily initialized in backward()
338	    model->grads_memory = NULL;
339	    model->workload_indices = NULL; // on cpu, for encoder_backward
340	    model->bucket_info = NULL; // on cpu, for encoder_backward
341	    // memory lazily initialized in update()
342	    model->m_memory = NULL;
343	    model->v_memory = NULL;
344	    model->master_weights = NULL;
345	    // other default settings
346	    model->rng_state = 13371337 + multi_gpu_config.process_rank; // used in stochastic rounding
347	    model->use_master_weights = 1; // safe default: do keep master weights in fp32
348	    model->init_state = true;
349	    model->recompute = 1; // good default: recompute gelu but not layernorm
350	    model->gelu_fusion = 0; //deviceProp.major >= 9 ? 2 : 0; // default: off for now (default must match main())
351	}
