353	void gpt2_allocate_weights(GPT2 *model) {
354	    // fill in all the parameter tensor dimensions and types
355	    fill_in_parameter_sizes(model->param_elements, model->param_sizeof, model->config);
356	    model->num_parameters = 0;
357	    model->num_parameters_bytes = 0;
358	    for (int i = 0; i < NUM_PARAMETER_TENSORS; i++) {
359	        model->num_parameters += model->param_elements[i];
360	        model->num_parameters_bytes += model->param_elements[i] * model->param_sizeof[i];
361	    }
362	    // create memory for model parameters on the device
363	    assert(model->params_memory == nullptr);
364	    model->params_memory = malloc_and_point_parameters(&model->params, model->param_elements, model->param_sizeof);
365	}
