129	// copy num_bytes from device pointer src into file dest, using double buffering running on the given stream.
130	inline void device_to_file(FILE* dest, void* src, size_t num_bytes, size_t buffer_size, cudaStream_t stream) {
131	    // allocate pinned buffer for faster, async transfer
132	    char* buffer_space;
133	    cudaCheck(cudaMallocHost(&buffer_space, 2*buffer_size));
134	    // split allocation in two
135	    void* read_buffer = buffer_space;
136	    void* write_buffer = buffer_space + buffer_size;
137	
138	    // prime the read buffer; first copy means we have to wait
139	    char* gpu_read_ptr = (char*)src;
140	    size_t copy_amount = std::min(buffer_size, num_bytes);
141	    cudaCheck(cudaMemcpyAsync(read_buffer, gpu_read_ptr, copy_amount, cudaMemcpyDeviceToHost, stream));
142	    cudaCheck(cudaStreamSynchronize(stream));
143	    size_t rest_bytes = num_bytes - copy_amount;
144	    size_t write_buffer_size = copy_amount;
145	    gpu_read_ptr += copy_amount;
146	
147	    std::swap(read_buffer, write_buffer);
148	    // now the main loop; as long as there are bytes left
149	    while(rest_bytes > 0) {
150	        // initiate next read
151	        copy_amount = std::min(buffer_size, rest_bytes);
152	        cudaCheck(cudaMemcpyAsync(read_buffer, gpu_read_ptr, copy_amount, cudaMemcpyDeviceToHost, stream));
153	        // while this is going on, transfer the write buffer to disk
154	        fwriteCheck(write_buffer, 1, write_buffer_size, dest);
155	        cudaCheck(cudaStreamSynchronize(stream));     // wait for both buffers to be ready.
156	
157	        std::swap(read_buffer, write_buffer);
158	        rest_bytes -= copy_amount;
159	        write_buffer_size = copy_amount;
160	        gpu_read_ptr += copy_amount;
161	    }
162	
163	    // make sure to write the last remaining write buffer
164	    fwriteCheck(write_buffer, 1, write_buffer_size, dest);
165	    cudaCheck(cudaFreeHost(buffer_space));
