134	template<typename Td, typename Ts>
135	__global__ void copy_and_cast_kernel(Td* dst, const Ts* src, size_t n, ptrdiff_t stride_dst, ptrdiff_t stride_src) {
136	    int idx = blockIdx.x * blockDim.x + threadIdx.x;
137	    // need to try grid stride looping for more perf later
138	    if (idx < n) {
139	        dst[idx + stride_dst * blockIdx.y] = cast_value<Td, Ts>(src[idx + stride_src * blockIdx.y]);
140	    }
141	}
