143	// ----------------------------------------------------------------------------
144	// Warp/Block communication primitives
145	
146	// warp-level reduction for summing values
147	__device__ inline float warpReduceSum(float val) {
148	    for (int offset = 16; offset > 0; offset /= 2) {
149	        val += __shfl_xor_sync(0xFFFFFFFF, val, offset);
150	    }
151	    return val;
152	}
153	// warp-level reduction for finding the maximum value
154	__device__ inline float warpReduceMax(float val) {
155	    for (int offset = 16; offset > 0; offset /= 2) {
156	        val = fmaxf(val, __shfl_xor_sync(0xFFFFFFFF, val, offset));
157	    }
158	    return val;
159	}
160	// requires all 32 threads in the warp to be active, but should work for any block size
161	// uses non-dynamic shared memory so every call increases shared memory requirements by 128 bytes
162	// the fact it's unique shared memory allows us to avoid an extra __syncthreads() call at the end
163	// but if called inside a loop, the shared memory will be implicitly reused, so set final_sync to 1
164	using reduction_func_t = float (*) (float);
165	template<reduction_func_t warp_reduction>
166	__device__ inline float blockReduce(float val, bool final_sync=false, float out_of_bounds=0.0f) {
167	    // two reductions of up to 1024 threads:
168	    // 1) inside warp (shuffle), 2) cross-warp (shared memory), 3) inside warp (shuffle)
169	    __shared__ float shared_val[WARP_SIZE];
170	    const int lane_id = threadIdx.x % WARP_SIZE;
171	    const int warp_id = threadIdx.x / WARP_SIZE;
172	    const int num_warps = blockDim.x / WARP_SIZE;
173	
174	    float warp_val = warp_reduction(val);
175	    if (lane_id == 0) { shared_val[warp_id] = warp_val; }
176	    __syncthreads();
177	    warp_val = (lane_id < num_warps) ? shared_val[lane_id] : out_of_bounds;
178	    float block_val = warp_reduction(warp_val);
179	
180	    if (final_sync) {
181	        __syncthreads(); // only needed in loops when effectively reusing shared memory etc.
182	    }
183	    return block_val;
184	}
185	
186	// Performs a _deterministic_ sum reduction. determinism is achieved by requiring that only
187	// a single block be used.
188	template<class Float>
189	__global__ void global_sum_single_block_kernel(float* result, const Float* values, size_t count) {
190	    assert(gridDim.x == 1);     // only a single block!
191	    float thread_sum = 0;
192	    for(size_t index = threadIdx.x; index < count; index += blockDim.x) {
193	        thread_sum += (float)values[index];
194	    }
195	
196	    float reduction = blockReduce<warpReduceSum>(thread_sum, true);
197	    if(threadIdx.x == 0) {
198	        *result = reduction;
199	    }
200	}
201	
202	template<class Float>
203	void global_sum_deterministic(float* result, const Float* values, int count, cudaStream_t stream) {
204	    global_sum_single_block_kernel<<<1, 1024, 0, stream>>>(result, values, count);
205	    cudaCheck(cudaGetLastError());
206	}
