211	// allocate memory, preferrably on the device
212	// returns a status code. 0 = OK, 1 = fell back to managed memory
213	int cudaMallocConditionallyManaged(void** out, size_t bytes, const char *file, int line) {
214	    // try to allocate
215	    cudaError_t err = cudaMalloc(out, bytes);
216	    if(err == cudaErrorMemoryAllocation) {
217	        // if we OOM, fallback to a managed allocation. slower but at least won't crash.
218	        cudaGetLastError(); // reset the error before the next API call
219	        cudaCheck_(cudaMallocManaged(out, bytes), file, line);
220	        cudaCheck_(cudaMemAdvise(*out, bytes, cudaMemAdviseSetPreferredLocation, cudaCpuDeviceId), file, line);
221	        return 1;
222	    } else {
223	        cudaCheck_(err, file, line);
224	        return 0;
225	    }
226	}
227	
228	#define cudaMallocConditionallyManaged(out, bytes)\
229	(cudaMallocConditionallyManaged((void**)out, bytes, __FILE__, __LINE__))
230	
231	// ----------------------------------------------------------------------------
232	// Random Number Generation used in Stochastic Rounding
233	
234	// SquirrelNoise5 - Squirrel's Raw Noise utilities (version 5)
235	// This gives us a random number from threadIdx/blockIdx + a single seed for the entire GPU
236	// todo - possibly overkill and we don't need such high quality random numbers? (tbd)
237	// http://eiserloh.net/noise/SquirrelNoise5.hpp
238	__device__ __host__ constexpr unsigned int SquirrelNoise5(unsigned int positionX, unsigned int seed)
239	{
240	    constexpr unsigned int SQ5_BIT_NOISE1 = 0xd2a80a3f;	// 11010010101010000000101000111111
241	    constexpr unsigned int SQ5_BIT_NOISE2 = 0xa884f197;	// 10101000100001001111000110010111
242	    constexpr unsigned int SQ5_BIT_NOISE3 = 0x6C736F4B; // 01101100011100110110111101001011
243	    constexpr unsigned int SQ5_BIT_NOISE4 = 0xB79F3ABB;	// 10110111100111110011101010111011
244	    constexpr unsigned int SQ5_BIT_NOISE5 = 0x1b56c4f5;	// 00011011010101101100010011110101
245	    unsigned int mangledBits = positionX;
246	    mangledBits *= SQ5_BIT_NOISE1;
247	    mangledBits += seed;
248	    mangledBits ^= (mangledBits >> 9);
249	    mangledBits += SQ5_BIT_NOISE2;
250	    mangledBits ^= (mangledBits >> 11);
251	    mangledBits *= SQ5_BIT_NOISE3;
252	    mangledBits ^= (mangledBits >> 13);
253	    mangledBits += SQ5_BIT_NOISE4;
254	    mangledBits ^= (mangledBits >> 15);
255	    mangledBits *= SQ5_BIT_NOISE5;
256	    mangledBits ^= (mangledBits >> 17);
257	    return mangledBits;
258	}
259	__device__ __host__ constexpr unsigned int Get2dNoiseUint(int indexX, int indexY, unsigned int seed)
260	{
261	    constexpr unsigned int PRIME_NUMBER = 198491317u; // Large prime number with non-boring bits
262	    unsigned int x = static_cast<unsigned int>(indexX);
263	    unsigned int y = static_cast<unsigned int>(indexY);
264	
265	    return SquirrelNoise5(x + (PRIME_NUMBER * y), seed);
266	}
267	
268	// stochastic rounding built on top of Squirel Noise above (with seed updated per step via xorshift)
269	__device__ __forceinline__ void stochastic_rounding(float in, __nv_bfloat16 *out, unsigned int seed) {
270	    // todo - is this stochastic rounding *too good*? can we cut any corners?
271	    // makes sure each thread gets a different random number
272	    unsigned int random = Get2dNoiseUint(threadIdx.x, blockIdx.x * blockDim.x + blockIdx.y, seed);
273	    unsigned int threshold = random & 0xFFFF;
274	    unsigned int float_bits = __float_as_uint(in);
275	    unsigned int rounded_bits = float_bits & 0x0000FFFF;
276	    float_bits = (rounded_bits > threshold) ? (float_bits | 0xFFFF) : (float_bits  & ~0xFFFF);
277	    *out = __float2bfloat16_rn(__uint_as_float(float_bits));
278	}
279	__device__ __forceinline__ void stochastic_rounding(float in, half *out, unsigned int random) {
280	    *out = (float)in; // todo - implement this...
281	}
282	__device__ __forceinline__ void stochastic_rounding(float in, float *out, unsigned int random) {
283	    *out = in; // dummy function for when floatX is float (FP32 mode)
284	}
285	
286	#endif

